private getSelectedRfqRows(): any[] {
  if (!this.params?.api) {
    return [];
  }

  const selectedNodes = this.params.api.getSelectedNodes() || [];
  const selectedRows = selectedNodes
    .filter((node: any) => !!node?.data)
    .map((node: any) => node.data);

  const uniqueRows = new Map<string, any>();
  const priceCodeField = this.getMasterFiledName('price_code') || 'Price Code';
  selectedRows.forEach((row: any) => {
    const rowKey = row?.id != null ? `id:${row.id}` : `pc:${row?.[priceCodeField]}`;
    if (rowKey && !uniqueRows.has(rowKey)) {
      uniqueRows.set(rowKey, row);
    }
  });

  return Array.from(uniqueRows.values());
}

