private setupVendorSubscription(): void {
  onSetVendorData.subscribe(data => {
    this.rowData = this.rowData.map(item => {
      if (item.id === data.row_id) {
        item.Vendors = item.Vendors.map(vendor =>
          vendor.id === data.Vendor.id ? data : vendor
        );
      }
      return item;
    });
  });
}

