async onReminder() {
  const selectedRowData = this.gridApi.getSelectedNodes();
  const sentVendors = new Set(); // ✅ Track vendor IDs to avoid duplicates
  let sentCount = 0;

  try {
    for (let i = 0; i < selectedRowData.length; i++) {
      const rowData = selectedRowData[i].data;
      if (!rowData || !rowData.Vendors) continue;

      for (let j = 0; j < rowData.Vendors.length; j++) {
        const vendorEntry = rowData.Vendors[j];
        if (vendorEntry.req_status != null) continue;

        const vendorId = vendorEntry.Vendor?.id;

        // ✅ Skip if this vendor was already emailed
        if (sentVendors.has(vendorId)) continue;
        sentVendors.add(vendorId);

        await firstValueFrom(this.itemService
          .sendPriceReq({
            id: vendorId,
            rfqItem_priceCode: vendorEntry.priceCode,
            sendEmail: true,
          }));
        sentCount++;
      }
    }
  } catch (err) {
    console.error('Failed to send reminder', err);
    this._snackBar.open('Failed to send reminder. Please try again.', 'ok', {
      duration: 4000,
    });
    return;
  }

  if (sentCount > 0) {
    this._snackBar.open(
      `Reminder was sent successfully to ${sentCount} vendor${sentCount === 1 ? '' : 's'}.`,
      'ok',
      { duration: 2000 },
    );
  } else {
    this._snackBar.open('No pending vendors to remind in the selected rows.', 'ok', {
      duration: 3000,
    });
  }
}

